def unpack_files():
    print("Checking and restoring project files...")
    for filepath, file_info in FILES_DATA.items():
        dirpath = os.path.dirname(filepath)
        if dirpath and not os.path.exists(dirpath):
            os.makedirs(dirpath, exist_ok=True)
            
        file_type = file_info["type"]
        content = file_info["content"]
        
        if file_type == "binary":
            # Only write binary if file doesn't exist
            if not os.path.exists(filepath):
                with open(filepath, "wb") as f:
                    f.write(base64.b64decode(content))
                print(f"  Restored binary: {filepath}")
        else:
            # For text, we can always overwrite or check
            with open(filepath, "w", encoding="utf-8") as f:
                f.write(content)
            print(f"  Restored text: {filepath}")
            
    print("All project files restored successfully.")

def run_dev_server():
    print("Starting Vite development server...")
    try:
        if os.name == 'nt':  # Windows
            subprocess.run("npm run dev", shell=True, check=True)
        else:
            subprocess.run(["npm", "run", "dev"], check=True)
    except KeyboardInterrupt:
        print("\nDev server stopped.")
    except Exception as e:
        print(f"Error launching dev server: {e}")

if __name__ == "__main__":
    unpack_files()
    run_dev_server()
